diff --git a/llvm/lib/Analysis/InstructionSimplify.cpp b/llvm/lib/Analysis/InstructionSimplify.cpp
index 2a1218a683ca..eabbcddf3bba 100644
--- a/llvm/lib/Analysis/InstructionSimplify.cpp
+++ b/llvm/lib/Analysis/InstructionSimplify.cpp
@@ -1709,6 +1709,90 @@ static Value *simplifyAndOrOfICmpsWithZero(ICmpInst *Cmp0, ICmpInst *Cmp1,

   return nullptr;
 }
+// For unsigned addition overflow checks:
+// (icmp ult/ule (X + Y), X) | (icmp ult/ule (X + Y), Y) --> one comparison
+// (icmp uge/ugt (X + Y), X) & (icmp uge/ugt (X + Y), Y) --> one comparison
+// This works because if the sum overflows, it's less than both addends;
+// if it doesn't overflow, it's >= both addends.
+static Value *simplifyAndOrOfICmpsWithUnsignedOverflow(ICmpInst *Op0,
+                                                       ICmpInst *Op1,
+                                                       bool IsAnd) {
+  ICmpInst::Predicate Pred0 = Op0->getPredicate();
+  ICmpInst::Predicate Pred1 = Op1->getPredicate();
+  Value *Op00 = Op0->getOperand(0);
+  Value *Op01 = Op0->getOperand(1);
+  Value *Op10 = Op1->getOperand(0);
+  Value *Op11 = Op1->getOperand(1);
+
+  // For OR: check for ULT or ULE predicates
+  // For AND: check for UGE or UGT predicates
+  if (IsAnd) {
+    if (Pred0 != ICmpInst::ICMP_UGE && Pred0 != ICmpInst::ICMP_UGT)
+      return nullptr;
+    if (Pred1 != ICmpInst::ICMP_UGE && Pred1 != ICmpInst::ICMP_UGT)
+      return nullptr;
+  } else {
+    if (Pred0 != ICmpInst::ICMP_ULT && Pred0 != ICmpInst::ICMP_ULE)
+      return nullptr;
+    if (Pred1 != ICmpInst::ICMP_ULT && Pred1 != ICmpInst::ICMP_ULE)
+      return nullptr;
+  }
+
+  // Check if both compare against the same sum (Op00 == Op10)
+  if (Op00 == Op10) {
+    if (auto *Add = dyn_cast<BinaryOperator>(Op00)) {
+      if (Add->getOpcode() == Instruction::Add) {
+        Value *AddOp0 = Add->getOperand(0);
+        Value *AddOp1 = Add->getOperand(1);
+        // Check if Op01 and Op11 are the two addends
+        if ((Op01 == AddOp0 && Op11 == AddOp1) ||
+            (Op01 == AddOp1 && Op11 == AddOp0))
+          return Op0;
+      }
+    }
+  }
+
+  // Check for swapped operands: (icmp ult X, (X+Y)) | (icmp ult Y, (X+Y))
+  if (Op01 == Op11) {
+    if (auto *Add = dyn_cast<BinaryOperator>(Op01)) {
+      if (Add->getOpcode() == Instruction::Add) {
+        Value *AddOp0 = Add->getOperand(0);
+        Value *AddOp1 = Add->getOperand(1);
+        if ((Op00 == AddOp0 && Op10 == AddOp1) ||
+            (Op00 == AddOp1 && Op10 == AddOp0))
+          return Op0;
+      }
+    }
+
+  // Check for cross operands: (icmp ule X, (X+Y)) & (icmp uge (X+Y), Y)
+  if (Op01 == Op10) {
+    if (auto *Add = dyn_cast<BinaryOperator>(Op01)) {
+      if (Add->getOpcode() == Instruction::Add) {
+        Value *AddOp0 = Add->getOperand(0);
+        Value *AddOp1 = Add->getOperand(1);
+        if ((Op00 == AddOp0 && Op11 == AddOp1) ||
+            (Op00 == AddOp1 && Op11 == AddOp0))
+          return Op0;
+      }
+    }
+  }
+
+  // Check for cross operands: (icmp uge (X+Y), X) & (icmp ule Y, (X+Y))
+  if (Op00 == Op11) {
+    if (auto *Add = dyn_cast<BinaryOperator>(Op00)) {
+      if (Add->getOpcode() == Instruction::Add) {
+        Value *AddOp0 = Add->getOperand(0);
+        Value *AddOp1 = Add->getOperand(1);
+        if ((Op01 == AddOp0 && Op10 == AddOp1) ||
+            (Op01 == AddOp1 && Op10 == AddOp0))
+          return Op0;
+      }
+    }
+  }
+
+
+  return nullptr;
+}

 static Value *simplifyAndOfICmpsWithAdd(ICmpInst *Op0, ICmpInst *Op1,
                                         const InstrInfoQuery &IIQ) {
@@ -1862,8 +1946,13 @@ static Value *simplifyAndOfICmps(ICmpInst *Op0, ICmpInst *Op1,
   if (Value *X = simplifyAndOfICmpsWithAdd(Op0, Op1, Q.IIQ))
     return X;
   if (Value *X = simplifyAndOfICmpsWithAdd(Op1, Op0, Q.IIQ))
+
+  if (Value *X = simplifyAndOrOfICmpsWithUnsignedOverflow(Op0, Op1, /*IsAnd=*/true))
+    return X;
+  if (Value *X = simplifyAndOrOfICmpsWithUnsignedOverflow(Op1, Op0, /*IsAnd=*/true))
     return X;

+
   return nullptr;
 }

@@ -1938,7 +2027,12 @@ static Value *simplifyOrOfICmps(ICmpInst *Op0, ICmpInst *Op1,
   if (Value *X = simplifyOrOfICmpsWithAdd(Op0, Op1, Q.IIQ))
     return X;
   if (Value *X = simplifyOrOfICmpsWithAdd(Op1, Op0, Q.IIQ))
+
+  if (Value *X = simplifyAndOrOfICmpsWithUnsignedOverflow(Op0, Op1, /*IsAnd=*/false))
     return X;
+  if (Value *X = simplifyAndOrOfICmpsWithUnsignedOverflow(Op1, Op0, /*IsAnd=*/false))
+    return X;
+

   return nullptr;
 }
diff --git a/llvm/lib/Analysis/ValueTracking.cpp b/llvm/lib/Analysis/ValueTracking.cpp
index 973943790c0a..4cbad79f7bfa 100644
--- a/llvm/lib/Analysis/ValueTracking.cpp
+++ b/llvm/lib/Analysis/ValueTracking.cpp
@@ -8291,6 +8291,21 @@ static std::optional<bool> isImpliedCondICmps(const ICmpInst *LHS,
   const APInt *LC, *RC;
   if (L0 == R0 && match(L1, m_APInt(LC)) && match(R1, m_APInt(RC)))
     return isImpliedCondCommonOperandWithConstants(LPred, *LC, RPred, *RC);
+  // Check if we have icmp ult/ule (X + Y), X and icmp ult/ule (X + Y), Y.
+  // If the sum is less than one addend, it must also be less than the other
+  // due to unsigned overflow, so either comparison implies the other.
+  if (L0 == R0 && (LPred == CmpInst::ICMP_ULT || LPred == CmpInst::ICMP_ULE) &&
+      (RPred == CmpInst::ICMP_ULT || RPred == CmpInst::ICMP_ULE)) {
+    if (auto *Add = dyn_cast<BinaryOperator>(L0)) {
+      if (Add->getOpcode() == Instruction::Add) {
+        Value *AddOp0 = Add->getOperand(0);
+        Value *AddOp1 = Add->getOperand(1);
+        // Check if L1 and R1 are the two addends (in any order)
+        if ((L1 == AddOp0 && R1 == AddOp1) || (L1 == AddOp1 && R1 == AddOp0))
+          return true;
+      }
+    }
+  }

   if (LPred == RPred)
     return isImpliedCondOperands(LPred, L0, L1, R0, R1, DL, Depth);
diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
index 703065280096..ec6bcf4bd34f 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
@@ -3070,13 +3070,44 @@ Value *InstCombinerImpl::foldAndOrOfICmps(ICmpInst *LHS, ICmpInst *RHS,
   // if K1 and K2 are a one-bit mask.
   if (Value *V = foldAndOrOfICmpsOfAndWithPow2(LHS, RHS, &I, IsAnd, IsLogical))
     return V;
-
   ICmpInst::Predicate PredL = LHS->getPredicate(), PredR = RHS->getPredicate();
   Value *LHS0 = LHS->getOperand(0), *RHS0 = RHS->getOperand(0);
   Value *LHS1 = LHS->getOperand(1), *RHS1 = RHS->getOperand(1);
   const APInt *LHSC = nullptr, *RHSC = nullptr;
   match(LHS1, m_APInt(LHSC));
   match(RHS1, m_APInt(RHSC));
+  // For unsigned comparisons, (icmp ult/ule (X + Y), X) | (icmp ult/ule (X + Y), Y)
+  // can be simplified to just one comparison because if the sum is less than one
+  // addend, it must also be less than the other due to unsigned overflow.
+  if (!IsAnd && !IsLogical &&
+      (PredL == ICmpInst::ICMP_ULT || PredL == ICmpInst::ICMP_ULE) &&
+      (PredR == ICmpInst::ICMP_ULT || PredR == ICmpInst::ICMP_ULE)) {
+    // Check if both compare against the same sum
+    if (LHS0 == RHS0) {
+      if (auto *Add = dyn_cast<BinaryOperator>(LHS0)) {
+        if (Add->getOpcode() == Instruction::Add) {
+          Value *AddOp0 = Add->getOperand(0);
+          Value *AddOp1 = Add->getOperand(1);
+          // Check if LHS1 and RHS1 are the two addends
+          if ((LHS1 == AddOp0 && RHS1 == AddOp1) ||
+              (LHS1 == AddOp1 && RHS1 == AddOp0))
+            return LHS;
+        }
+      }
+    }
+    // Check for swapped operands: (icmp ult X, (X+Y)) | (icmp ult Y, (X+Y))
+    if (LHS1 == RHS1) {
+      if (auto *Add = dyn_cast<BinaryOperator>(LHS1)) {
+        if (Add->getOpcode() == Instruction::Add) {
+          Value *AddOp0 = Add->getOperand(0);
+          Value *AddOp1 = Add->getOperand(1);
+          if ((LHS0 == AddOp0 && RHS0 == AddOp1) ||
+              (LHS0 == AddOp1 && RHS0 == AddOp0))
+            return LHS;
+        }
+      }
+    }
+  }

   // (icmp1 A, B) | (icmp2 A, B) --> (icmp3 A, B)
   // (icmp1 A, B) & (icmp2 A, B) --> (icmp3 A, B)

